import { mkdirSync } from "node:fs";
import path from "node:path";
import { DatabaseSync, type SQLInputValue } from "node:sqlite";
import {
  defaultContent,
  defaultFleet,
  defaultProjects,
  defaultReferences,
  defaultServices,
  defaultSettings,
  defaultSlides,
  type FleetItem,
  type HeroSlide,
  type Project,
  type ReferenceCompany,
  type Service,
  type SiteSettings,
  type SiteContent,
} from "./content-data";

type D1Result<T> = { results?: T[] };
type D1Statement = {
  bind: (...values: unknown[]) => D1Statement;
  all: <T>() => Promise<D1Result<T>>;
  first: <T>() => Promise<T | null>;
  run: () => Promise<unknown>;
};
type D1DatabaseLike = {
  prepare: (sql: string) => D1Statement;
  batch: (statements: D1Statement[]) => Promise<unknown>;
};

export type AdminEntity = "projects" | "services" | "references" | "fleet" | "slides" | "settings";

type SqliteGlobal = typeof globalThis & {
  __ulucanSqlite?: D1DatabaseLike;
  __ulucanDbReady?: Promise<void>;
};

function database(): D1DatabaseLike {
  const globalStore = globalThis as SqliteGlobal;
  if (globalStore.__ulucanSqlite) return globalStore.__ulucanSqlite;

  const filename = process.env.SQLITE_PATH || path.join(/*turbopackIgnore: true*/ process.cwd(), "data", "ulucan.sqlite");
  mkdirSync(path.dirname(filename), { recursive: true });
  const sqlite = new DatabaseSync(filename);
  sqlite.exec("PRAGMA journal_mode = WAL");
  sqlite.exec("PRAGMA busy_timeout = 5000");
  sqlite.exec("PRAGMA foreign_keys = ON");

  const wrapped: D1DatabaseLike = {
    prepare(sql: string) {
      let values: SQLInputValue[] = [];
      return {
        bind(...next: unknown[]) { values = next as SQLInputValue[]; return this; },
        async all<T>() { return { results: sqlite.prepare(sql).all(...values) as T[] }; },
        async first<T>() { return (sqlite.prepare(sql).get(...values) as T | undefined) ?? null; },
        async run() { return sqlite.prepare(sql).run(...values); },
      };
    },
    async batch(statements) {
      sqlite.exec("BEGIN IMMEDIATE");
      try {
        for (const statement of statements) await statement.run();
        sqlite.exec("COMMIT");
      } catch (error) {
        sqlite.exec("ROLLBACK");
        throw error;
      }
      return [];
    },
  };
  globalStore.__ulucanSqlite = wrapped;
  return wrapped;
}

async function initializeDatabase(db: D1DatabaseLike) {
  await db.batch([
    db.prepare(`CREATE TABLE IF NOT EXISTS projects (
      id TEXT PRIMARY KEY, slug TEXT NOT NULL UNIQUE, title TEXT NOT NULL,
      summary TEXT NOT NULL DEFAULT '', description TEXT NOT NULL DEFAULT '',
      location TEXT NOT NULL DEFAULT '', client TEXT NOT NULL DEFAULT '',
      status TEXT NOT NULL DEFAULT 'ongoing', start_date TEXT NOT NULL,
      end_date TEXT, year INTEGER NOT NULL, cover_image_url TEXT NOT NULL DEFAULT '',
      gallery_urls TEXT NOT NULL DEFAULT '[]', youtube_url TEXT NOT NULL DEFAULT '',
      project_website_url TEXT NOT NULL DEFAULT '',
      featured INTEGER NOT NULL DEFAULT 0, sort_order INTEGER NOT NULL DEFAULT 0
    )`),
    db.prepare("CREATE INDEX IF NOT EXISTS projects_year_idx ON projects (year DESC, sort_order ASC)"),
    db.prepare(`CREATE TABLE IF NOT EXISTS services (
      id TEXT PRIMARY KEY, title TEXT NOT NULL, summary TEXT NOT NULL DEFAULT '',
      number TEXT NOT NULL DEFAULT '01', sort_order INTEGER NOT NULL DEFAULT 0
    )`),
    db.prepare(`CREATE TABLE IF NOT EXISTS "references" (
      id TEXT PRIMARY KEY, name TEXT NOT NULL, logo_url TEXT NOT NULL DEFAULT '',
      website_url TEXT NOT NULL DEFAULT '', featured INTEGER NOT NULL DEFAULT 0,
      sort_order INTEGER NOT NULL DEFAULT 0
    )`),
    db.prepare(`CREATE TABLE IF NOT EXISTS fleet (
      id TEXT PRIMARY KEY, name TEXT NOT NULL, category TEXT NOT NULL DEFAULT '',
      brand_model TEXT NOT NULL DEFAULT '', quantity INTEGER NOT NULL DEFAULT 1,
      verified INTEGER NOT NULL DEFAULT 0, image_url TEXT NOT NULL DEFAULT '', sort_order INTEGER NOT NULL DEFAULT 0
    )`),
    db.prepare(`CREATE TABLE IF NOT EXISTS hero_slides (
      id TEXT PRIMARY KEY, image_url TEXT NOT NULL DEFAULT '',
      alt_text TEXT NOT NULL DEFAULT 'Ulucan saha çalışması',
      active INTEGER NOT NULL DEFAULT 1, sort_order INTEGER NOT NULL DEFAULT 0
    )`),
    db.prepare(`CREATE TABLE IF NOT EXISTS site_settings (
      id TEXT PRIMARY KEY, hero_eyebrow TEXT NOT NULL DEFAULT '',
      hero_title_top TEXT NOT NULL DEFAULT '', hero_title_accent TEXT NOT NULL DEFAULT '',
      hero_title_bottom TEXT NOT NULL DEFAULT '', hero_description TEXT NOT NULL DEFAULT '',
      intro_eyebrow TEXT NOT NULL DEFAULT '', intro_title TEXT NOT NULL DEFAULT '',
      intro_title_accent TEXT NOT NULL DEFAULT '', intro_description TEXT NOT NULL DEFAULT '',
      services_title TEXT NOT NULL DEFAULT '', services_title_accent TEXT NOT NULL DEFAULT '',
      projects_title TEXT NOT NULL DEFAULT '', projects_title_accent TEXT NOT NULL DEFAULT '',
      references_title TEXT NOT NULL DEFAULT '', header_logo_url TEXT NOT NULL DEFAULT '',
      emblem_logo_url TEXT NOT NULL DEFAULT '', footer_logo_url TEXT NOT NULL DEFAULT '',
      founding_year TEXT NOT NULL DEFAULT '', certificates_text TEXT NOT NULL DEFAULT '',
      seo_title TEXT NOT NULL DEFAULT '', seo_description TEXT NOT NULL DEFAULT '',
      google_site_verification TEXT NOT NULL DEFAULT '',
      instagram_url TEXT NOT NULL DEFAULT '', facebook_url TEXT NOT NULL DEFAULT '',
      linkedin_url TEXT NOT NULL DEFAULT '', youtube_channel_url TEXT NOT NULL DEFAULT '',
      corporate_title TEXT NOT NULL DEFAULT '', corporate_text TEXT NOT NULL DEFAULT ''
    )`),
    db.prepare(`CREATE TABLE IF NOT EXISTS page_views (
      id TEXT PRIMARY KEY, session_id TEXT NOT NULL, masked_ip TEXT NOT NULL DEFAULT '',
      path TEXT NOT NULL, referrer TEXT NOT NULL DEFAULT '', user_agent TEXT NOT NULL DEFAULT '',
      started_at TEXT NOT NULL, ended_at TEXT, duration_seconds INTEGER NOT NULL DEFAULT 0
    )`),
    db.prepare("CREATE INDEX IF NOT EXISTS page_views_started_idx ON page_views (started_at DESC)"),
    db.prepare(`CREATE TABLE IF NOT EXISTS audit_logs (
      id TEXT PRIMARY KEY, actor_email TEXT NOT NULL, action TEXT NOT NULL,
      entity TEXT NOT NULL, record_id TEXT NOT NULL DEFAULT '', masked_ip TEXT NOT NULL DEFAULT '',
      created_at TEXT NOT NULL
    )`),
    db.prepare("CREATE INDEX IF NOT EXISTS audit_logs_created_idx ON audit_logs (created_at DESC)"),
    db.prepare(`CREATE TABLE IF NOT EXISTS quote_requests (
      id TEXT PRIMARY KEY, name TEXT NOT NULL, company TEXT NOT NULL DEFAULT '',
      phone TEXT NOT NULL DEFAULT '', email TEXT NOT NULL DEFAULT '', project_type TEXT NOT NULL DEFAULT '',
      location TEXT NOT NULL DEFAULT '', message TEXT NOT NULL DEFAULT '', fingerprint TEXT NOT NULL DEFAULT '',
      status TEXT NOT NULL DEFAULT 'new', created_at TEXT NOT NULL
    )`),
    db.prepare("CREATE INDEX IF NOT EXISTS quote_requests_created_idx ON quote_requests (created_at DESC)"),
  ]);

  for (const statement of [
    "ALTER TABLE fleet ADD COLUMN verified INTEGER NOT NULL DEFAULT 0",
    "ALTER TABLE site_settings ADD COLUMN founding_year TEXT NOT NULL DEFAULT ''",
    "ALTER TABLE site_settings ADD COLUMN certificates_text TEXT NOT NULL DEFAULT ''",
    "ALTER TABLE site_settings ADD COLUMN seo_title TEXT NOT NULL DEFAULT ''",
    "ALTER TABLE site_settings ADD COLUMN seo_description TEXT NOT NULL DEFAULT ''",
    "ALTER TABLE site_settings ADD COLUMN google_site_verification TEXT NOT NULL DEFAULT ''",
    "ALTER TABLE site_settings ADD COLUMN instagram_url TEXT NOT NULL DEFAULT ''",
    "ALTER TABLE site_settings ADD COLUMN facebook_url TEXT NOT NULL DEFAULT ''",
    "ALTER TABLE site_settings ADD COLUMN linkedin_url TEXT NOT NULL DEFAULT ''",
    "ALTER TABLE site_settings ADD COLUMN youtube_channel_url TEXT NOT NULL DEFAULT ''",
    "ALTER TABLE site_settings ADD COLUMN corporate_title TEXT NOT NULL DEFAULT ''",
    "ALTER TABLE site_settings ADD COLUMN corporate_text TEXT NOT NULL DEFAULT ''",
  ]) {
    try { await db.prepare(statement).run(); } catch { /* Column already exists. */ }
  }

  const existing = await db.prepare("SELECT COUNT(*) AS count FROM projects").first<{ count: number }>();
  const statements: D1Statement[] = [];
  if ((existing?.count ?? 0) === 0) for (const item of defaultProjects) {
    statements.push(db.prepare(`INSERT OR IGNORE INTO projects
      (id, slug, title, summary, description, location, client, status, start_date, end_date, year, cover_image_url, gallery_urls, youtube_url, project_website_url, featured, sort_order)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`)
      .bind(item.id, item.slug, item.title, item.summary, item.description, item.location, item.client, item.status, item.startDate, item.endDate || null, item.year, item.coverImageUrl, JSON.stringify(item.galleryUrls), item.youtubeUrl, item.projectWebsiteUrl, item.featured ? 1 : 0, item.sortOrder));
  }
  if ((existing?.count ?? 0) === 0) for (const item of defaultServices) {
    statements.push(db.prepare("INSERT OR IGNORE INTO services (id, title, summary, number, sort_order) VALUES (?, ?, ?, ?, ?)")
      .bind(item.id, item.title, item.summary, item.number, item.sortOrder));
  }
  if ((existing?.count ?? 0) === 0) for (const item of defaultReferences) {
    statements.push(db.prepare('INSERT OR IGNORE INTO "references" (id, name, logo_url, website_url, featured, sort_order) VALUES (?, ?, ?, ?, ?, ?)')
      .bind(item.id, item.name, item.logoUrl, item.websiteUrl, item.featured ? 1 : 0, item.sortOrder));
  }
  if ((existing?.count ?? 0) === 0) for (const item of defaultFleet) {
    statements.push(db.prepare("INSERT OR IGNORE INTO fleet (id, name, category, brand_model, quantity, verified, image_url, sort_order) VALUES (?, ?, ?, ?, ?, ?, ?, ?)")
      .bind(item.id, item.name, item.category, item.brandModel, item.quantity, item.verified ? 1 : 0, item.imageUrl, item.sortOrder));
  }
  for (const item of defaultSlides) {
    statements.push(db.prepare("INSERT OR IGNORE INTO hero_slides (id, image_url, alt_text, active, sort_order) VALUES (?, ?, ?, ?, ?)")
      .bind(item.id, item.imageUrl, item.altText, item.active ? 1 : 0, item.sortOrder));
  }
  const s = defaultSettings;
  statements.push(db.prepare(`INSERT OR IGNORE INTO site_settings
    (id, hero_eyebrow, hero_title_top, hero_title_accent, hero_title_bottom, hero_description,
    intro_eyebrow, intro_title, intro_title_accent, intro_description, services_title,
    services_title_accent, projects_title, projects_title_accent, references_title,
    header_logo_url, emblem_logo_url, footer_logo_url, founding_year, certificates_text,
    seo_title, seo_description, google_site_verification, instagram_url, facebook_url,
    linkedin_url, youtube_channel_url, corporate_title, corporate_text)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`)
    .bind(s.id, s.heroEyebrow, s.heroTitleTop, s.heroTitleAccent, s.heroTitleBottom, s.heroDescription,
      s.introEyebrow, s.introTitle, s.introTitleAccent, s.introDescription, s.servicesTitle,
      s.servicesTitleAccent, s.projectsTitle, s.projectsTitleAccent, s.referencesTitle,
      s.headerLogoUrl, s.emblemLogoUrl, s.footerLogoUrl, s.foundingYear, s.certificatesText,
      s.seoTitle, s.seoDescription, s.googleSiteVerification, s.instagramUrl, s.facebookUrl,
      s.linkedinUrl, s.youtubeChannelUrl, s.corporateTitle, s.corporateText));
  await db.batch(statements);
}

export async function ensureDatabase(db: D1DatabaseLike) {
  const globalStore = globalThis as SqliteGlobal;
  if (!globalStore.__ulucanDbReady) {
    globalStore.__ulucanDbReady = initializeDatabase(db).catch((error) => {
      delete globalStore.__ulucanDbReady;
      throw error;
    });
  }
  await globalStore.__ulucanDbReady;
}

function parseGallery(value: unknown): string[] {
  try {
    const parsed = JSON.parse(String(value ?? "[]"));
    return Array.isArray(parsed) ? parsed.filter((item): item is string => typeof item === "string") : [];
  } catch {
    return [];
  }
}

export async function getSiteContent(): Promise<SiteContent> {
  const db = database();
  try {
    await ensureDatabase(db);
    const [projectRows, serviceRows, referenceRows, fleetRows, slideRows, settingsRow] = await Promise.all([
      db.prepare("SELECT * FROM projects ORDER BY CASE WHEN sort_order <= 0 THEN 999999 ELSE sort_order END ASC, year DESC, start_date DESC").all<Record<string, unknown>>(),
      db.prepare("SELECT * FROM services ORDER BY sort_order ASC").all<Record<string, unknown>>(),
      db.prepare('SELECT * FROM "references" ORDER BY sort_order ASC').all<Record<string, unknown>>(),
      db.prepare("SELECT * FROM fleet ORDER BY sort_order ASC").all<Record<string, unknown>>(),
      db.prepare("SELECT * FROM hero_slides ORDER BY sort_order ASC").all<Record<string, unknown>>(),
      db.prepare("SELECT * FROM site_settings WHERE id = 'homepage'").first<Record<string, unknown>>(),
    ]);
    const projects = (projectRows.results ?? []).map((row): Project => ({
      id: String(row.id), slug: String(row.slug), title: String(row.title), summary: String(row.summary),
      description: String(row.description), location: String(row.location), client: String(row.client),
      status: row.status === "completed" ? "completed" : "ongoing", startDate: String(row.start_date),
      endDate: String(row.end_date ?? ""), year: Number(row.year), coverImageUrl: String(row.cover_image_url),
      galleryUrls: parseGallery(row.gallery_urls), youtubeUrl: String(row.youtube_url ?? ""), projectWebsiteUrl: String(row.project_website_url ?? ""),
      featured: Boolean(row.featured), sortOrder: Number(row.sort_order),
    }));
    const services = (serviceRows.results ?? []).map((row): Service => ({ id: String(row.id), title: String(row.title), summary: String(row.summary), number: String(row.number), sortOrder: Number(row.sort_order) }));
    const references = (referenceRows.results ?? []).map((row): ReferenceCompany => ({ id: String(row.id), name: String(row.name), logoUrl: String(row.logo_url), websiteUrl: String(row.website_url), featured: Boolean(row.featured), sortOrder: Number(row.sort_order) }));
    const fleet = (fleetRows.results ?? []).map((row): FleetItem => ({ id: String(row.id), name: String(row.name), category: String(row.category), brandModel: String(row.brand_model), quantity: Number(row.quantity), verified: Boolean(row.verified), imageUrl: String(row.image_url), sortOrder: Number(row.sort_order) }));
    const slides = (slideRows.results ?? []).map((row): HeroSlide => ({ id: String(row.id), imageUrl: String(row.image_url), altText: String(row.alt_text), active: Boolean(row.active), sortOrder: Number(row.sort_order) }));
    const row = settingsRow ?? {};
    const settings: SiteSettings = {
      id: "homepage", heroEyebrow: String(row.hero_eyebrow ?? defaultSettings.heroEyebrow),
      heroTitleTop: String(row.hero_title_top ?? defaultSettings.heroTitleTop), heroTitleAccent: String(row.hero_title_accent ?? defaultSettings.heroTitleAccent),
      heroTitleBottom: String(row.hero_title_bottom ?? defaultSettings.heroTitleBottom), heroDescription: String(row.hero_description ?? defaultSettings.heroDescription),
      introEyebrow: String(row.intro_eyebrow ?? defaultSettings.introEyebrow), introTitle: String(row.intro_title ?? defaultSettings.introTitle),
      introTitleAccent: String(row.intro_title_accent ?? defaultSettings.introTitleAccent), introDescription: String(row.intro_description ?? defaultSettings.introDescription),
      servicesTitle: String(row.services_title ?? defaultSettings.servicesTitle), servicesTitleAccent: String(row.services_title_accent ?? defaultSettings.servicesTitleAccent),
      projectsTitle: String(row.projects_title ?? defaultSettings.projectsTitle), projectsTitleAccent: String(row.projects_title_accent ?? defaultSettings.projectsTitleAccent),
      referencesTitle: String(row.references_title ?? defaultSettings.referencesTitle), headerLogoUrl: String(row.header_logo_url ?? defaultSettings.headerLogoUrl),
      emblemLogoUrl: String(row.emblem_logo_url ?? defaultSettings.emblemLogoUrl), footerLogoUrl: String(row.footer_logo_url ?? defaultSettings.footerLogoUrl),
      foundingYear: String(row.founding_year ?? defaultSettings.foundingYear), certificatesText: String(row.certificates_text ?? defaultSettings.certificatesText),
      seoTitle: String(row.seo_title ?? defaultSettings.seoTitle), seoDescription: String(row.seo_description ?? defaultSettings.seoDescription),
      googleSiteVerification: String(row.google_site_verification ?? defaultSettings.googleSiteVerification),
      instagramUrl: String(row.instagram_url ?? defaultSettings.instagramUrl),
      facebookUrl: String(row.facebook_url ?? defaultSettings.facebookUrl),
      linkedinUrl: String(row.linkedin_url ?? defaultSettings.linkedinUrl),
      youtubeChannelUrl: String(row.youtube_channel_url ?? defaultSettings.youtubeChannelUrl),
      corporateTitle: String(row.corporate_title || defaultSettings.corporateTitle),
      corporateText: String(row.corporate_text || defaultSettings.corporateText),
    };
    return { projects, services, references, fleet, slides, settings };
  } catch {
    return defaultContent;
  }
}

export async function saveEntity(entity: AdminEntity, payload: Record<string, unknown>) {
  const db = database();
  await ensureDatabase(db);
  const id = String(payload.id || crypto.randomUUID());
  if (entity === "projects") {
    const slug = String(payload.slug || payload.title || id).toLocaleLowerCase("tr-TR").normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/ı/g, "i").replace(/[^a-z0-9]+/g, "-").replace(/(^-|-$)/g, "");
    await db.prepare(`INSERT INTO projects (id, slug, title, summary, description, location, client, status, start_date, end_date, year, cover_image_url, gallery_urls, youtube_url, project_website_url, featured, sort_order)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
      ON CONFLICT(id) DO UPDATE SET slug=excluded.slug, title=excluded.title, summary=excluded.summary, description=excluded.description, location=excluded.location, client=excluded.client, status=excluded.status, start_date=excluded.start_date, end_date=excluded.end_date, year=excluded.year, cover_image_url=excluded.cover_image_url, gallery_urls=excluded.gallery_urls, youtube_url=excluded.youtube_url, project_website_url=excluded.project_website_url, featured=excluded.featured, sort_order=excluded.sort_order`)
      .bind(id, slug, String(payload.title || "Yeni Proje"), String(payload.summary || ""), String(payload.description || ""), String(payload.location || ""), String(payload.client || ""), payload.status === "completed" ? "completed" : "ongoing", String(payload.startDate || new Date().toISOString().slice(0, 10)), payload.endDate ? String(payload.endDate) : null, Number(payload.year || new Date().getFullYear()), String(payload.coverImageUrl || ""), JSON.stringify(Array.isArray(payload.galleryUrls) ? payload.galleryUrls : []), String(payload.youtubeUrl || ""), String(payload.projectWebsiteUrl || ""), payload.featured ? 1 : 0, Number(payload.sortOrder || 0)).run();
  } else if (entity === "services") {
    await db.prepare("INSERT INTO services (id, title, summary, number, sort_order) VALUES (?, ?, ?, ?, ?) ON CONFLICT(id) DO UPDATE SET title=excluded.title, summary=excluded.summary, number=excluded.number, sort_order=excluded.sort_order")
      .bind(id, String(payload.title || "Yeni Hizmet"), String(payload.summary || ""), String(payload.number || "01"), Number(payload.sortOrder || 0)).run();
  } else if (entity === "references") {
    await db.prepare('INSERT INTO "references" (id, name, logo_url, website_url, featured, sort_order) VALUES (?, ?, ?, ?, ?, ?) ON CONFLICT(id) DO UPDATE SET name=excluded.name, logo_url=excluded.logo_url, website_url=excluded.website_url, featured=excluded.featured, sort_order=excluded.sort_order')
      .bind(id, String(payload.name || "Yeni Referans"), String(payload.logoUrl || ""), String(payload.websiteUrl || ""), payload.featured ? 1 : 0, Number(payload.sortOrder || 0)).run();
  } else if (entity === "fleet") {
    await db.prepare("INSERT INTO fleet (id, name, category, brand_model, quantity, verified, image_url, sort_order) VALUES (?, ?, ?, ?, ?, ?, ?, ?) ON CONFLICT(id) DO UPDATE SET name=excluded.name, category=excluded.category, brand_model=excluded.brand_model, quantity=excluded.quantity, verified=excluded.verified, image_url=excluded.image_url, sort_order=excluded.sort_order")
      .bind(id, String(payload.name || "Yeni Makine"), String(payload.category || ""), String(payload.brandModel || ""), Number(payload.quantity ?? 0), payload.verified ? 1 : 0, String(payload.imageUrl || ""), Number(payload.sortOrder || 0)).run();
  } else if (entity === "slides") {
    await db.prepare("INSERT INTO hero_slides (id, image_url, alt_text, active, sort_order) VALUES (?, ?, ?, ?, ?) ON CONFLICT(id) DO UPDATE SET image_url=excluded.image_url, alt_text=excluded.alt_text, active=excluded.active, sort_order=excluded.sort_order")
      .bind(id, String(payload.imageUrl || ""), String(payload.altText || "Ulucan saha çalışması"), payload.active === false ? 0 : 1, Number(payload.sortOrder || 0)).run();
  } else {
    const s = { ...defaultSettings, ...payload, id: "homepage" } as SiteSettings;
    await db.prepare(`INSERT INTO site_settings
      (id, hero_eyebrow, hero_title_top, hero_title_accent, hero_title_bottom, hero_description,
      intro_eyebrow, intro_title, intro_title_accent, intro_description, services_title,
      services_title_accent, projects_title, projects_title_accent, references_title,
      header_logo_url, emblem_logo_url, footer_logo_url, founding_year, certificates_text,
      seo_title, seo_description, google_site_verification, instagram_url, facebook_url,
      linkedin_url, youtube_channel_url, corporate_title, corporate_text)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
      ON CONFLICT(id) DO UPDATE SET hero_eyebrow=excluded.hero_eyebrow,
      hero_title_top=excluded.hero_title_top, hero_title_accent=excluded.hero_title_accent,
      hero_title_bottom=excluded.hero_title_bottom, hero_description=excluded.hero_description,
      intro_eyebrow=excluded.intro_eyebrow, intro_title=excluded.intro_title,
      intro_title_accent=excluded.intro_title_accent, intro_description=excluded.intro_description,
      services_title=excluded.services_title, services_title_accent=excluded.services_title_accent,
      projects_title=excluded.projects_title, projects_title_accent=excluded.projects_title_accent,
      references_title=excluded.references_title, header_logo_url=excluded.header_logo_url,
      emblem_logo_url=excluded.emblem_logo_url, footer_logo_url=excluded.footer_logo_url,
      founding_year=excluded.founding_year, certificates_text=excluded.certificates_text,
      seo_title=excluded.seo_title, seo_description=excluded.seo_description,
      google_site_verification=excluded.google_site_verification,
      instagram_url=excluded.instagram_url, facebook_url=excluded.facebook_url,
      linkedin_url=excluded.linkedin_url, youtube_channel_url=excluded.youtube_channel_url,
      corporate_title=excluded.corporate_title, corporate_text=excluded.corporate_text`)
      .bind("homepage", s.heroEyebrow, s.heroTitleTop, s.heroTitleAccent, s.heroTitleBottom, s.heroDescription,
        s.introEyebrow, s.introTitle, s.introTitleAccent, s.introDescription, s.servicesTitle,
        s.servicesTitleAccent, s.projectsTitle, s.projectsTitleAccent, s.referencesTitle,
        s.headerLogoUrl, s.emblemLogoUrl, s.footerLogoUrl, s.foundingYear, s.certificatesText,
        s.seoTitle, s.seoDescription, s.googleSiteVerification, s.instagramUrl, s.facebookUrl,
        s.linkedinUrl, s.youtubeChannelUrl, s.corporateTitle, s.corporateText).run();
  }
  return id;
}

export async function deleteEntity(entity: AdminEntity, id: string) {
  const db = database();
  await ensureDatabase(db);
  if (entity === "settings") return;
  const table = entity === "references" ? '"references"' : entity === "slides" ? "hero_slides" : entity;
  await db.prepare(`DELETE FROM ${table} WHERE id = ?`).bind(id).run();
}

export async function reorderEntities(entity: Exclude<AdminEntity, "settings">, orderedIds: string[]) {
  const db = database();
  await ensureDatabase(db);
  const table = entity === "references" ? '"references"' : entity === "slides" ? "hero_slides" : entity;
  const ids = [...new Set(orderedIds.map(String).filter(Boolean))];
  if (!ids.length || ids.length > 500) throw new Error("Geçersiz sıralama listesi.");
  await db.batch(ids.map((id, index) => db.prepare(`UPDATE ${table} SET sort_order = ? WHERE id = ?`).bind(index + 1, id)));
}

export type PageViewInput = {
  id: string; sessionId: string; maskedIp: string; path: string;
  referrer: string; userAgent: string; startedAt: string;
};

export async function startPageView(input: PageViewInput) {
  const db = database();
  await ensureDatabase(db);
  await db.prepare(`INSERT OR IGNORE INTO page_views
    (id, session_id, masked_ip, path, referrer, user_agent, started_at, duration_seconds)
    VALUES (?, ?, ?, ?, ?, ?, ?, 0)`)
    .bind(input.id, input.sessionId, input.maskedIp, input.path.slice(0, 500), input.referrer.slice(0, 1000), input.userAgent.slice(0, 500), input.startedAt).run();
  await db.prepare("DELETE FROM page_views WHERE started_at < datetime('now', '-90 days')").run();
}

export async function finishPageView(id: string, durationSeconds: number, endedAt: string) {
  const db = database();
  await ensureDatabase(db);
  const safeDuration = Math.max(0, Math.min(Math.round(durationSeconds), 86400));
  await db.prepare("UPDATE page_views SET ended_at = ?, duration_seconds = ? WHERE id = ?")
    .bind(endedAt, safeDuration, id).run();
}

export async function logAdminAction(input: { actorEmail: string; action: string; entity: string; recordId: string; maskedIp: string }) {
  const db = database();
  await ensureDatabase(db);
  await db.prepare(`INSERT INTO audit_logs
    (id, actor_email, action, entity, record_id, masked_ip, created_at)
    VALUES (?, ?, ?, ?, ?, ?, ?)`)
    .bind(crypto.randomUUID(), input.actorEmail, input.action, input.entity, input.recordId, input.maskedIp, new Date().toISOString()).run();
  await db.prepare("DELETE FROM audit_logs WHERE created_at < datetime('now', '-365 days')").run();
}

export type QuoteRequestInput = {
  name: string; company: string; phone: string; email: string;
  projectType: string; location: string; message: string; fingerprint: string;
};

export async function recentQuoteRequestCount(fingerprint: string) {
  const db = database();
  await ensureDatabase(db);
  const row = await db.prepare("SELECT COUNT(*) AS count FROM quote_requests WHERE fingerprint = ? AND created_at >= datetime('now', '-1 hour')")
    .bind(fingerprint).first<{ count: number }>();
  return Number(row?.count ?? 0);
}

export async function saveQuoteRequest(input: QuoteRequestInput) {
  const db = database();
  await ensureDatabase(db);
  const id = crypto.randomUUID();
  await db.prepare(`INSERT INTO quote_requests
    (id, name, company, phone, email, project_type, location, message, fingerprint, status, created_at)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, 'new', ?)`)
    .bind(id, input.name, input.company, input.phone, input.email, input.projectType, input.location, input.message, input.fingerprint, new Date().toISOString()).run();
  return id;
}

export type QuoteRequestRecord = QuoteRequestInput & { id: string; status: string; createdAt: string };

export async function getQuoteRequests(): Promise<QuoteRequestRecord[]> {
  const db = database();
  await ensureDatabase(db);
  const rows = await db.prepare("SELECT * FROM quote_requests ORDER BY created_at DESC LIMIT 250").all<Record<string, unknown>>();
  return (rows.results ?? []).map((row) => ({
    id: String(row.id), name: String(row.name), company: String(row.company), phone: String(row.phone),
    email: String(row.email), projectType: String(row.project_type), location: String(row.location),
    message: String(row.message), fingerprint: String(row.fingerprint), status: String(row.status), createdAt: String(row.created_at),
  }));
}

export type AnalyticsData = {
  totals: { views: number; sessions: number; averageSeconds: number };
  pageViews: Array<{ id: string; sessionId: string; maskedIp: string; path: string; referrer: string; userAgent: string; startedAt: string; durationSeconds: number }>;
  auditLogs: Array<{ id: string; actorEmail: string; action: string; entity: string; recordId: string; maskedIp: string; createdAt: string }>;
};

export async function getAnalyticsData(): Promise<AnalyticsData> {
  const db = database();
  await ensureDatabase(db);
  const [total, views, audits] = await Promise.all([
    db.prepare("SELECT COUNT(*) AS views, COUNT(DISTINCT session_id) AS sessions, COALESCE(AVG(duration_seconds), 0) AS average_seconds FROM page_views").first<Record<string, unknown>>(),
    db.prepare("SELECT * FROM page_views ORDER BY started_at DESC LIMIT 250").all<Record<string, unknown>>(),
    db.prepare("SELECT * FROM audit_logs ORDER BY created_at DESC LIMIT 250").all<Record<string, unknown>>(),
  ]);
  return {
    totals: { views: Number(total?.views ?? 0), sessions: Number(total?.sessions ?? 0), averageSeconds: Math.round(Number(total?.average_seconds ?? 0)) },
    pageViews: (views.results ?? []).map((row) => ({ id: String(row.id), sessionId: String(row.session_id), maskedIp: String(row.masked_ip), path: String(row.path), referrer: String(row.referrer), userAgent: String(row.user_agent), startedAt: String(row.started_at), durationSeconds: Number(row.duration_seconds) })),
    auditLogs: (audits.results ?? []).map((row) => ({ id: String(row.id), actorEmail: String(row.actor_email), action: String(row.action), entity: String(row.entity), recordId: String(row.record_id), maskedIp: String(row.masked_ip), createdAt: String(row.created_at) })),
  };
}
